def union_find(n: int, edges: list) -> int:
    parent = list(range(n))
    rank = [0] * n

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def unite(a, b):
        a, b = find(a), find(b)
        if a == b: return
        if rank[a] < rank[b]: a, b = b, a
        parent[b] = a
        if rank[a] == rank[b]: rank[a] += 1

    for a, b in edges:
        unite(a, b)
    return sum(1 for i in range(n) if find(i) == i)

