fn union_find(n: Int, edges: List[Tuple[Int,Int]]) -> Int:
    var parent = List[Int]()
    var rank_ = List[Int]()
    for i in range(n):
        parent.append(i); rank_.append(0)

    fn find(x: Int) -> Int:
        var cur = x
        while parent[cur] != cur:
            parent[cur] = parent[parent[cur]]
            cur = parent[cur]
        return cur

    for edge in edges:
        var a = find(edge[].get[0,Int]())
        var b = find(edge[].get[1,Int]())
        if a == b: continue
        if rank_[a] < rank_[b]:
            var tmp = a; a = b; b = tmp
        parent[b] = a
        if rank_[a] == rank_[b]: rank_[a] += 1

    var comps = 0
    for i in range(n):
        if find(i) == i: comps += 1
    return comps
